var e=JSON.parse(`[{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"성찬을 준비하라. 새로운 날이 당도하리니.","JPN":"聖餐を準備しろ。新しい日が到来する。","ENG":"Prepare the feast. A new dawn is coming.","TWN":"預備盛宴吧。新天已來到。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"불완전한 지식, 불완전한 존재들이 성찬을 통해 하나가 되어, 완전해질 것이다.","JPN":"不完全な知識、不完全な存在たちが聖餐により一つになり、完全体となる。","ENG":"The feast will complete the imperfect knowledge and perfect the imperfect beings.","TWN":"不完整的知識，不完整的存在將透過盛宴合而為一，變得完整。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"모두 지식의 성찬을 준비하라.\\n모두 연회를 시작하라.","JPN":"みんな、知識の聖餐を準備しろ。\\nみんな、宴会を始めろ。","ENG":"[[","TWN":"大家準備知識的盛宴吧，\\n大家開始宴會吧。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"오랜 갈구와 허기의 끝이 마침내 도래했다.","JPN":"長い渇きと飢えの果てが、ついに訪れたのだ。","ENG":"The long thirst and hunger are finally coming to an end.","TWN":"長久的渴望和饑餓終於到達了盡頭。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"오늘의 성찬은 어린 양의 피와 살일지니.\\n삼키는 자가 삼켜지고, 삼켜지는 자가 삼키리라.","JPN":"今日は子羊の血と肉が聖餐となり、\\n飲み込む者が飲み込まれ、飲み込まれる者が飲み込むことになるだろう。","ENG":"[[","TWN":"今天的盛宴，是羔羊的血和肉。\\n吞食者將被吞噬，被吞噬者將去吞食。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"연회는 아직인가.","JPN":"宴会はまだか。","ENG":"When shall the banquet begin?","TWN":"宴會還沒開始嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"성찬의 주인이 도착했다. 어머니께서 도래하였다.","JPN":"聖餐の主が到着した。お母さんのお出ましだ。","ENG":"The host of the feast has arrived. Mother has arrived.","TWN":"盛宴的主人到了，母親到了。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"내 이름과 명예를 걸고 너희에게 맹세하마.","JPN":"俺の名前と名誉をかけて、お前たちに誓おう。","ENG":"I swear on my name and honor.","TWN":"我以我的名字和榮譽為賭注，向你們發誓。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"아무리 힘들어도, 아무리 오랜 시간이 걸려도 너희를 포기하지 않겠다.","JPN":"どんなに辛い思いをしても、どんなに長い時間がかかっても、俺はお前たちのことを諦めない。","ENG":"No matter how hard, no matter how long, I won't give up on you.","TWN":"無論多累，會花費多少時間，我也不會放棄你們。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"그러니 지금은.","JPN":"だから今は……","ENG":"So for now.","TWN":"所以現在……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRYDWEN_ESPR_QM","text":{"KOREA":"지금은 조금만 우리를 믿고 기다려 줄 수 있겠니?","JPN":"今は俺たちを信じて、待ってくれないか。","ENG":"Could you trust us and wait a bit?","TWN":"可以相信我，再等我們一會兒嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"또 그 꿈이야.","JPN":"また同じ夢だ。","ENG":"It's that dream again.","TWN":"又是那個夢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"꿈을 꾸면, 꿀수록 이미지가 선명해지고 있어.","JPN":"夢を見れば見るほど、鮮明になってきてる。","ENG":"The more I dream about it, the clearer the image gets.","TWN":"夢做得越多，畫面就越清晰。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다는 뜻은…….","JPN":"ということは……","ENG":"Which means...","TWN":"意思是……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"원장실에서 테오도라 수녀님의 이야기를 엿듣게 된 뒤로.","JPN":"院長室からテオドラさんの話を盗み聞きした後。","ENG":"After eavesdropping on Sister Theodora in her office...","TWN":"在院長室偷聽了狄奧朵拉修女的話之後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"우리는 로젠탈에서 탈출할 계획을 세웠다.","JPN":"私たちはローゼンタールから脱出する計画を立てた。","ENG":"We made a plan to escape from Rosenthal.","TWN":"我們建立了逃離羅森泰計畫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"……뭐라고?","JPN":"……え？","ENG":"...What?","TWN":"……你說什麼？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"여기 애들을 놓고 갈 수는 없어.","JPN":"この子たちを置いては行けないよ。","ENG":"We can't just leave the other children here.","TWN":"不能把孩子們丟在這裡。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"부탁이야, 앤. 이곳에서 도망치려면 다 같이 도망치자.","JPN":"お願い、アン。ここから逃げるなら、みんなで逃げよう。","ENG":"Please, Ann. If we're going to run away, let's run away all together!","TWN":"我求求你，安妮。想從這裡逃走，就帶著大家一起逃吧。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그건 무리야.","JPN":"それは無理。","ENG":"We can't.","TWN":"那太勉強了。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"전에 말했잖아. 보육원의 배후에는 정체 모를 세력이 있다고.","JPN":"前に言ったでしょ？　保育園の背後には、得体の知れない勢力があるって。","ENG":"I told you. There is an unknown force behind the orphanage.","TWN":"我之前跟你說過，育幼院的背後有不明的勢力。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"우리 둘만 튀는 것도 붙잡힐 가능성이 큰데, 애들을 다 데려가겠다고?","JPN":"私たちだけで逃げても捕まる可能性は高いのに、子どもたちをみんな連れて行くつもり？","ENG":"Our chances of getting caught are already high with just us two, but you want all the other kids with you too?","TWN":"光是我們二個跑了也很有可能被抓，你卻還想把他們都帶走？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};